          "code": "public class QuickSort {\n    public static void sort(int[] arr, int low, int high) {\n        // Input: Array 'arr', boundary limits 'low' and 'high'\n        if (low < high) {\n            // Process: Find partitioning index\n            int pivotIndex = partition(arr, low, high);\n            \n            // Process: Recursive calls\n            sort(arr, low, pivotIndex - 1);  // Left partition\n            sort(arr, pivotIndex + 1, high); // Right partition\n        }\n    }\n    \n    private static int partition(int[] arr, int low, int high) {\n        // Storage: Pivot selection\n        int pivot = arr[high]; \n        int i = (low - 1); // Index of smaller element\n        \n        // Process: Swapping elements based on pivot comparison\n        for (int j = low; j < high; j++) {\n            if (arr[j] < pivot) {\n                i++;\n                int temp = arr[i];\n                arr[i] = arr[j];\n                arr[j] = temp;\n            }\n        }\n        \n        // Process: Swap pivot to its final sorted place\n        int temp = arr[i + 1];\n        arr[i + 1] = arr[high];\n        arr[high] = temp;\n        \n        // Output: Return partition index\n        return i + 1; \n    }\n}",
