          "code": "public class HeapSort {\n    public static void sort(int[] arr) {\n        // Input: Array to sort\n        int n = arr.length; // Storage\n        \n        // Process: Build heap (rearrange array)\n        for (int i = n / 2 - 1; i >= 0; i--) {\n            heapify(arr, n, i);\n        }\n        \n        // Process: Extract elements from heap\n        for (int i = n - 1; i > 0; i--) {\n            // Swap current root to end\n            int temp = arr[0];\n            arr[0] = arr[i];\n            arr[i] = temp;\n            \n            // Heapify root node\n            heapify(arr, i, 0);\n        }\n    }\n    \n    private static void heapify(int[] arr, int n, int i) {\n        // Storage: heap variables\n        int largest = i;\n        int l = 2 * i + 1;\n        int r = 2 * i + 2;\n        \n        // Process: Check child limits\n        if (l < n && arr[l] > arr[largest]) largest = l;\n        if (r < n && arr[r] > arr[largest]) largest = r;\n        \n        if (largest != i) {\n            int swap = arr[i];\n            arr[i] = arr[largest];\n            arr[largest] = swap;\n            \n            heapify(arr, n, largest);\n        }\n    }\n}",
