          "code": "import java.util.Arrays;\n\npublic class RadixSort {\n    public static void sort(int[] arr) {\n        // Input: Array to sort\n        int n = arr.length; // Storage\n        \n        // Process: Find max value to determine digits count\n        int max = arr[0];\n        for (int i = 1; i < n; i++) {\n            if (arr[i] > max) max = arr[i];\n        }\n        \n        // Process: Run counting sort for each digit place (exp)\n        for (int exp = 1; max / exp > 0; exp *= 10) {\n            countSort(arr, n, exp);\n        }\n    }\n    \n    private static void countSort(int[] arr, int n, int exp) {\n        // Storage: output and count array\n        int[] output = new int[n];\n        int[] count = new int[10];\n        Arrays.fill(count, 0);\n        \n        // Process: Count frequencies\n        for (int i = 0; i < n; i++) {\n            count[(arr[i] / exp) % 10]++;\n        }\n        for (int i = 1; i < 10; i++) {\n            count[i] += count[i - 1];\n        }\n        for (int i = n - 1; i >= 0; i--) {\n            output[count[(arr[i] / exp) % 10] - 1] = arr[i];\n            count[(arr[i] / exp) % 10]--;\n        }\n        for (int i = 0; i < n; i++) {\n            arr[i] = output[i];\n        }\n    }\n}",
