          "code": "public class ShellSort {\n    public static void sort(int[] arr) {\n        // Input: Array parameter\n        int n = arr.length; // Storage\n        \n        // Process: Shrink gaps\n        for (int gap = n / 2; gap > 0; gap /= 2) {\n            // Perform insertion sort on gapped sub-lists\n            for (int i = gap; i < n; i++) {\n                int temp = arr[i]; // Storage\n                int j = i;         // Storage\n                \n                while (j >= gap && arr[j - gap] > temp) {\n                    arr[j] = arr[j - gap]; // Process: Shift values\n                    j -= gap;\n                }\n                arr[j] = temp; // Process: Insert in slot\n            }\n        }\n    }\n}",
