          "code": "public class CycleDetector {\n    public static boolean hasCycle(SinglyLinkedList.Node head) {\n        // Input: Head node\n        if (head == null) return false;\n        \n        // Storage: Slow and fast pointers\n        SinglyLinkedList.Node slow = head;\n        SinglyLinkedList.Node fast = head;\n        \n        // Process: Floyd's tortoise and hare loops\n        while (fast != null && fast.next != null) {\n            slow = slow.next;          // Step 1\n            fast = fast.next.next;     // Step 2\n            \n            if (slow == fast) {\n                return true; // Output: Cycle detected\n            }\n        }\n        return false; // Output: No cycle\n    }\n}",
